import React, { useRef, useEffect, useState } from 'react';
import {
  AppBar, Toolbar, Typography, IconButton, Drawer, List, ListItem, ListItemText, Divider, Box, Slider, Input, Button, Modal, styled
} from '@mui/material';
import {
  Brush as BrushIcon,
  Undo as UndoIcon,
  Redo as RedoIcon,
  Delete as DeleteIcon,
  ColorLens as ColorLensIcon,
  Help as HelpIcon,
  Code as CodeIcon
} from '@mui/icons-material';
import { shapeDefinitions, defaultShape, drawGridAndAxes, drawFigure } from './shapes';

const drawerWidth = 300;

const Canvas = styled('canvas')({
  width: '100%',
  height: 'calc(100vh - 64px)',
  backgroundColor: '#fff',
  cursor: 'crosshair'
});

const ToolbarButton = styled(IconButton)({
  margin: '0 4px',
  color: 'white'
});

function App() {
  const canvasRef = useRef(null);
  const [figures, setFigures] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const [selectedShape, setSelectedShape] = useState(defaultShape);
  const [shapeParams, setShapeParams] = useState({});
  const [color, setColor] = useState('#4f46e5');
  const [lineWidth, setLineWidth] = useState(2);
  const [drawerOpen, setDrawerOpen] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [mouseCoords, setMouseCoords] = useState({ x: '--', y: '--' });
  const [history, setHistory] = useState([]);
  const [historyIndex, setHistoryIndex] = useState(-1);

  // Draw grid and axes
  const drawGridAndAxes = (ctx, width, height) => {
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, width, height);
    
    // Grid
    ctx.save();
    ctx.strokeStyle = '#e0e0e0';
    ctx.lineWidth = 0.5;
    const gridSpacing = 20;
    for (let x = 0; x <= width; x += gridSpacing) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, height); ctx.stroke();
    }
    for (let y = 0; y <= height; y += gridSpacing) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(width, y); ctx.stroke();
    }
    
    // Axes
    ctx.strokeStyle = '#888';
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(width/2, 0); ctx.lineTo(width/2, height); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(0, height/2); ctx.lineTo(width, height/2); ctx.stroke();
    ctx.restore();
  };

  // Redraw canvas with all figures
  const redrawCanvas = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const width = canvas.width;
    const height = canvas.height;

    drawGridAndAxes(ctx, width, height);

    // Draw all figures
    figures.forEach(fig => {
      ctx.save();
      ctx.strokeStyle = fig.color;
      ctx.lineWidth = fig.lineWidth;
      ctx.fillStyle = fig.color;

      const centerX = width / 2;
      const centerY = height / 2;

      switch (fig.type) {
        case 'point':
          ctx.beginPath();
          ctx.arc(centerX + fig.params.x, centerY - fig.params.y, 3, 0, 2 * Math.PI);
          ctx.fill();
          break;

        case 'line':
          ctx.beginPath();
          ctx.moveTo(centerX + fig.params.x1, centerY - fig.params.y1);
          ctx.lineTo(centerX + fig.params.x2, centerY - fig.params.y2);
          ctx.stroke();
          break;

        case 'circle':
          ctx.beginPath();
          ctx.arc(centerX + fig.params.centerX, centerY - fig.params.centerY, fig.params.radius, 0, 2 * Math.PI);
          ctx.stroke();
          break;

        case 'rectangle':
          ctx.beginPath();
          ctx.rect(
            centerX + fig.params.centerX - fig.params.width/2,
            centerY - fig.params.centerY - fig.params.height/2,
            fig.params.width,
            fig.params.height
          );
          ctx.stroke();
          break;

        case 'triangle':
          ctx.beginPath();
          ctx.moveTo(centerX + fig.params.x1, centerY - fig.params.y1);
          ctx.lineTo(centerX + fig.params.x2, centerY - fig.params.y2);
          ctx.lineTo(centerX + fig.params.x3, centerY - fig.params.y3);
          ctx.closePath();
          ctx.stroke();
          break;

        case 'ellipse':
          ctx.beginPath();
          ctx.ellipse(
            centerX + fig.params.centerX,
            centerY - fig.params.centerY,
            fig.params.radiusX,
            fig.params.radiusY,
            0, 0, 2 * Math.PI
          );
          ctx.stroke();
          break;
      }
      ctx.restore();
    });
  };

  // Initialize canvas and redraw on mount
  useEffect(() => {
    redrawCanvas();
  }, [figures]);

  // Mouse coordinate display
  const handleMouseMove = (e) => {
    const rect = canvasRef.current.getBoundingClientRect();
    const x = Math.round(e.clientX - rect.left - canvasRef.current.width/2);
    const y = Math.round(canvas.height/2 - (e.clientY - rect.top));
    setMouseCoords({ x, y });
  };

  const handleMouseLeave = () => setMouseCoords({ x: '--', y: '--' });

  // Handle drawing
  const handleDraw = () => {
    if (selectedShape === 'select') {
      alert('Please select a shape first');
      return;
    }

    // Validate all parameters are filled
    const def = shapeDefinitions[selectedShape];
    const allParamsFilled = def.params.every(param => 
      shapeParams[param.name] !== undefined && shapeParams[param.name] !== ''
    );

    if (!allParamsFilled) {
      alert('Please fill all parameters');
      return;
    }

    // Add new figure
    const newFigure = {
      type: selectedShape,
      params: { ...shapeParams },
      color,
      lineWidth
    };

    const newFigures = [...figures, newFigure];
    setFigures(newFigures);
    setRedoStack([]); // Clear redo stack when new figure is drawn
    setHistory([...history.slice(0, historyIndex + 1), newFigures]);
    setHistoryIndex(historyIndex + 1);
  };

  // Handle undo
  const handleUndo = () => {
    if (historyIndex > 0) {
      setHistoryIndex(historyIndex - 1);
      setFigures(history[historyIndex - 1]);
    }
  };

  // Handle redo
  const handleRedo = () => {
    if (historyIndex < history.length - 1) {
      setHistoryIndex(historyIndex + 1);
      setFigures(history[historyIndex + 1]);
    }
  };

  // Handle clear
  const handleClear = () => {
    setFigures([]);
    setRedoStack([]);
    setHistory([]);
    setHistoryIndex(-1);
  };

  // Handle keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.ctrlKey) {
        switch (e.key.toLowerCase()) {
          case 'd':
            e.preventDefault();
            handleDraw();
            break;
          case 'z':
            e.preventDefault();
            handleUndo();
            break;
          case 'y':
            e.preventDefault();
            handleRedo();
            break;
          case 'c':
            e.preventDefault();
            handleClear();
            break;
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedShape, shapeParams, color, lineWidth]);

  return (
    <Box sx={{ display: 'flex' }}>
      <AppBar position="fixed" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}>
        <Toolbar>
          <Typography variant="h6" noWrap component="div" sx={{ flexGrow: 1 }}>
            Draze Visualizer
          </Typography>
          <ToolbarButton onClick={handleUndo}>
            <UndoIcon />
          </ToolbarButton>
          <ToolbarButton onClick={handleRedo}>
            <RedoIcon />
          </ToolbarButton>
          <ToolbarButton onClick={handleClear}>
            <DeleteIcon />
          </ToolbarButton>
          <ToolbarButton>
            <CodeIcon />
          </ToolbarButton>
          <ToolbarButton>
            <HelpIcon />
          </ToolbarButton>
        </Toolbar>
      </AppBar>

      <Drawer
        variant="permanent"
        sx={{
          width: drawerWidth,
          flexShrink: 0,
          '& .MuiDrawer-paper': {
            width: drawerWidth,
            boxSizing: 'border-box',
            marginTop: '64px'
          },
        }}
      >
        <List>
          {Object.entries(shapeDefinitions).map(([key, shape]) => (
            <ListItem
              button
              key={key}
              selected={selectedShape === key}
              onClick={() => { setSelectedShape(key); setShapeParams({}); }}
            >
              <ListItemText primary={shape.text} />
            </ListItem>
          ))}
        </List>

        {selectedShape !== 'select' && (
          <Box sx={{ p: 2 }}>
            {shapeDefinitions[selectedShape].params.map(param => (
              <Input
                key={param.name}
                type="number"
                placeholder={param.label}
                value={shapeParams[param.name] || ''}
                onChange={(e) => setShapeParams({ ...shapeParams, [param.name]: e.target.value })}
                sx={{ width: '100%', marginBottom: 12 }}
              />
            ))}
            <Input
              type="color"
              value={color}
              onChange={(e) => setColor(e.target.value)}
              sx={{ width: '100%', marginBottom: 2 }}
            />
            <Typography gutterBottom>Line Width</Typography>
            <Slider
              value={lineWidth}
              onChange={(_, value) => setLineWidth(value)}
              min={1}
              max={10}
              step={1}
              marks
            />
            <Box sx={{ mt: 2 }}>
              <Typography variant="body2">
                Mouse Position: ({mouseCoords.x.toFixed(0)}, {mouseCoords.y.toFixed(0)})
              </Typography>
            </Box>
          </Box>
        )}
      </Drawer>

      <Box component="main" sx={{ flexGrow: 1, p: 3, marginTop: '64px' }}>
        <Paper elevation={3} sx={{ p: 2 }}>
          <Canvas
            ref={canvasRef}
            width={800}
            height={600}
            style={{ border: '1px solid #e5e7eb', background: '#fff', borderRadius: 6 }}
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            onClick={handleDraw}
          />
        </Paper>
      </Box>

      <Modal open={modalOpen} onClose={() => setModalOpen(false)}>
        <Box sx={{ 
          position: 'absolute',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          width: 400,
          bgcolor: 'background.paper',
          boxShadow: 24,
          p: 4,
          borderRadius: 2
        }}>
          <Typography variant="h6" component="h2" sx={{ mb: 2 }}>User Manual</Typography>
          <Typography variant="body2" sx={{ mb: 2 }}>
            Welcome to Draze! This tool allows you to draw various geometric shapes on a canvas.
          </Typography>
          <Typography variant="subtitle2" sx={{ mb: 1 }}>Keyboard Shortcuts:</Typography>
          <Typography variant="body2" component="div" sx={{ mb: 2 }}>
            • Ctrl+D: Draw the selected figure<br />
            • Ctrl+Z: Undo the last action<br />
            • Ctrl+Y: Redo the last undone action<br />
            • Ctrl+C: Clear all figures
          </Typography>
          <Typography variant="subtitle2" sx={{ mb: 1 }}>Basic Usage:</Typography>
          <Typography variant="body2" component="div" sx={{ mb: 2 }}>
            1. Select a figure type from the dropdown<br />
            2. Enter the required dimensions<br />
            3. Choose a color and line thickness<br />
            4. Click Draw or press Ctrl+D<br />
            5. View JSON in the Figure Data panel<br />
            6. Use Undo, Redo, and Clear as needed
          </Typography>
          <Button onClick={() => setModalOpen(false)} variant="contained" sx={{ mt: 2 }}>Close</Button>
        </Box>
      </Modal>
    </Box>
  );
}

export default App;
